# --- Observer Pattern ---
class Subject:
    def __init__(self): self.observers = []
    def attach(self, obs): self.observers.append(obs)
    def notify(self, data):
        for obs in self.observers: obs.update(data)

class Logger(Observer):
    def update(self, data): print(f"Log: {data}")
